import{_ as t,o as d,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"功能详解","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md","lastUpdated":1783223243000}'),r={name:"guide/features.md"};function s(c,e,i,l,h,n){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h1><p>CZero 的每项功能都可在 <code>config.json</code> 中单独开关，并由守护进程按各自的计划触发。本页说明每个功能<strong>具体做了什么、如何触发、有哪些保护机制</strong>。</p><h2 id="缓存清理" tabindex="-1">缓存清理 <a class="header-anchor" href="#缓存清理" aria-label="Permalink to &quot;缓存清理&quot;">​</a></h2><p>为高频应用（微信、QQ、抖音）提供各自独立的清理器，按 <code>app_clean.detect_schedule</code> 的频率触发。</p><h3 id="触发前的检测" tabindex="-1">触发前的检测 <a class="header-anchor" href="#触发前的检测" aria-label="Permalink to &quot;触发前的检测&quot;">​</a></h3><p>每次触发时，<code>check</code> 会先判断应用当前状态，避免无谓或有害的清理：</p><ul><li><strong>只清理&quot;该清的&quot;应用</strong> —— 通过读取 <code>/dev/cpuset/top-app</code> 与 <code>dumpsys activity</code>（<code>ResumedActivity</code>）识别前台应用；结合 <code>oom_score_adj</code> 判定前台主进程。</li><li><strong>前台应用不清理</strong> —— 当某应用正处于前台使用时，本轮跳过它，避免影响正在进行的操作。</li><li><strong>游戏前台保护</strong> —— 内置一份常见游戏包名清单，当前台是游戏时不执行清理，避免打断游戏。</li></ul><h3 id="每个应用的开关" tabindex="-1">每个应用的开关 <a class="header-anchor" href="#每个应用的开关" aria-label="Permalink to &quot;每个应用的开关&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wechat&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enhanced&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><ul><li><code>enabled</code> —— 是否清理该应用。</li><li><code>enhanced</code> —— <strong>增强模式</strong>。开启后清理更彻底（范围更广），默认关闭以求稳妥。</li></ul><h3 id="其他应用清理" tabindex="-1">其他应用清理 <a class="header-anchor" href="#其他应用清理" aria-label="Permalink to &quot;其他应用清理&quot;">​</a></h3><p><code>app_clean.other</code> 处理三大应用之外的缓存，按其 <code>schedule</code> 定时执行（默认每天 03:00）。</p><h3 id="总开关与时序屏障" tabindex="-1">总开关与时序屏障 <a class="header-anchor" href="#总开关与时序屏障" aria-label="Permalink to &quot;总开关与时序屏障&quot;">​</a></h3><ul><li>受总开关 <code>general.auto_clean</code> 控制。</li><li>受 <code>general.temporal_barrier_days</code>（<strong>时序屏障</strong>）保护：只清理 N 天以前的文件，保护近期数据；设为 <code>0</code> 表示不启用。</li></ul><h2 id="后台压制" tabindex="-1">后台压制 <a class="header-anchor" href="#后台压制" aria-label="Permalink to &quot;后台压制&quot;">​</a></h2><p>按 <code>suppress.detect_schedule</code> 的频率周期性压制在后台运行的目标应用。</p><p>工作方式：遍历 <code>/proc</code> 找到目标应用的后台进程并结束它们（<code>SIGKILL</code>），从而释放内存、减少后台耗电。关键保护：</p><ul><li><strong>前台应用绝不动</strong> —— 正在前台的应用不会被压制。</li><li><strong>识别不到前台就不压制</strong> —— 若本轮无法确定前台应用，则跳过，避免误伤。</li><li>压制次数计入统计（<code>basis.prop</code> 的 <code>suppress</code>）。</li></ul><h2 id="f2fs-垃圾回收" tabindex="-1">F2FS 垃圾回收 <a class="header-anchor" href="#f2fs-垃圾回收" aria-label="Permalink to &quot;F2FS 垃圾回收&quot;">​</a></h2><p>监控 F2FS 文件系统的脏段数量，超过阈值时执行垃圾回收（GC）。为安全起见，GC 会等待屏幕熄灭后再运行，并限制最长运行时间。</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>dirty_threshold</code></td><td>脏段 <strong>大于</strong> 此值时触发 GC（须大于 <code>clean_threshold</code>）</td></tr><tr><td><code>clean_threshold</code></td><td>脏段 <strong>小于</strong> 此值时视为清理完成并停止</td></tr><tr><td><code>wait_screen_off_timeout</code></td><td>等待息屏的超时（秒），到点仍亮屏则本轮放弃</td></tr><tr><td><code>max_runtime_sec</code></td><td>单次 GC 的最长运行时长（秒），到时强制停止</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">为什么要等息屏</p><p>F2FS GC 属于磁盘密集操作，放在息屏、设备空闲时执行可以避免影响前台使用的流畅度。</p></div><blockquote><p>GC 功能需要 <code>/data</code> 为 F2FS 分区。非 F2FS 设备可将 <code>gc.enabled</code> 设为 <code>false</code>，其余功能不受影响。</p></blockquote><h2 id="空文件夹清理" tabindex="-1">空文件夹清理 <a class="header-anchor" href="#空文件夹清理" aria-label="Permalink to &quot;空文件夹清理&quot;">​</a></h2><p>按 <code>empty_folder.schedule</code> 定时清扫残留的空目录（默认每天 04:00）。清扫范围由 <code>list/Emptyfolder/directories.prop</code> 定义，并受白名单 <code>emptyfolder_white.prop</code> 约束。</p><h2 id="自定义路径清理" tabindex="-1">自定义路径清理 <a class="header-anchor" href="#自定义路径清理" aria-label="Permalink to &quot;自定义路径清理&quot;">​</a></h2><p>除内置规则外，你可以声明自己的清理路径，由每日任务统一清扫：</p><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><code>list/clean_paths.prop</code></td><td>自定义要清理的路径列表</td></tr><tr><td><code>list/clean_whitelist.prop</code></td><td>清理白名单（保护不被清理的路径）</td></tr></tbody></table><p>这些列表可通过 CZeroX 的规则编辑器管理，重装模块时也会被继承。</p><h2 id="统计与日志" tabindex="-1">统计与日志 <a class="header-anchor" href="#统计与日志" aria-label="Permalink to &quot;统计与日志&quot;">​</a></h2><ul><li><p><strong>统计</strong> —— 各应用的清理次数、压制次数记录在 <code>basis/basis.prop</code>；CZeroX 主页展示今日与累计数据。每天 00:00 由 <code>zero</code> 任务重置当日计数。</p></li><li><p><strong>日志</strong> —— 开启 <code>general.log</code> 后，所有组件写入单一的每日日志 <code>log/&lt;YYYY-MM-DD&gt;.log</code>，每条带来源标签：</p><table tabindex="0"><thead><tr><th>标签</th><th>来源</th></tr></thead><tbody><tr><td><code>[定时]</code></td><td>调度守护进程</td></tr><tr><td><code>[检测]</code></td><td>前台检测</td></tr><tr><td><code>[微信]</code> <code>[QQ]</code> <code>[抖音]</code></td><td>各应用清理</td></tr><tr><td><code>[压制]</code></td><td>后台压制</td></tr><tr><td><code>[GC]</code></td><td>F2FS 垃圾回收</td></tr><tr><td><code>[空文件夹]</code></td><td>空文件夹清理</td></tr><tr><td><code>[自定义]</code></td><td>自定义路径清理</td></tr></tbody></table><p>仅保留当天日志（<code>zero</code> 任务会删除非今日的日志文件）。</p></li></ul><p>两者默认关闭，可随时开启或关闭。</p><h2 id="超级岛通知" tabindex="-1">超级岛通知 <a class="header-anchor" href="#超级岛通知" aria-label="Permalink to &quot;超级岛通知&quot;">​</a></h2><p>清理器在开始与结束时可向 CZeroX 广播事件（<code>CleanEventReceiver</code>），用于在应用侧显示执行进度 / 结果通知（含超级岛）。此行为可由环境变量 <code>CZERO_NO_NOTIFY=1</code> 关闭。</p>',34)])])}const b=t(r,[["render",s]]);export{u as __pageData,b as default};
